#include<bits/stdc++.h>
using namespace std;
bool hefa(string s){
	for(int i=1;i<s.size();i++){
		if(s[i]<s[i-1])return false;
	}
	return true;

}
pair<char,char>a[10000];
int main()
{
	int t;
	cin>>t;
	while(t--){
		int n;
		cin>>n;
		string s[105];
		int flag=0;
		for(int i=0;i<n;i++){
			cin>>s[i];
			if(!hefa(s[i])){
				flag=1;
			}
			a[i]={s[i][0],s[i][s[i].size()-1]};
		}
		if(flag){
			cout<<0<<endl;
			continue;
		}
		sort(a,a+n);
		for(int i=1;i<n;i++){
			if(a[i].first<a[i-1].second){
				cout<<0<<endl; 
				flag=1;
				break;
			}
		}
		if(flag)continue;
		cout<<1<<endl;
	}
}
